import React, { useState } from "react";

function App() {

  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");


  // When form submited, check with db if the username 
  const handleSubmit_find_user = async (e) => {
    e.preventDefault();


    // variable to check login being true
    const response = await fetch("http://localhost:9000/testAPI/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        name: username,
        password: password
      })
    });

    const data = await response.json();
    if(data.exists){
      setMessage("User found");
    }
    else{
      setMessage("User doesn't exist")
    }
  };


//--------------------------Register a user-------------------------------
const handleSubmit_register = async (e) => {
    e.preventDefault();


    // variable to check login being true
    const response = await fetch("http://localhost:9000/testAPI/user", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        name: username,
        age : age,
        password: password

      })
    });

    const data = await response.json();
    if(data.exists){
      setMessage("User found");
    }
    else{
      setMessage("User doesn't exist")
    }
  };


  return (
    <div className="App">
      <h2>Search for a user </h2>

      <form onSubmit={handleSubmit_find_user}>
        <label htmlFor="name">username :</label>
        <input
          type="text"
          id="name"
          name="name"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <br />

        <label htmlFor="password">password :</label>
        <input
          type="text"
          id="password"
          name="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <br />
        <br />

        <input type="submit" value="Submit" />
      </form>

      <p>{message}</p>
    </div>
  );
}







export default App;
